// Script: generar_68_datepicker.js
// Que hace: reemplaza el selector de fecha nativo del celular
// (input type="date", incomodo de usar en movil) por un picker visual
// propio con:
//   - Grid 4x3 de meses para elegir el mes de un vistazo
//   - Grid de dias del mes seleccionado
//   - Navegacion de ano con flechas
//   - Modal que sube desde abajo (misma estetica que los demas
//     modales de la app)
//   - Boton que muestra la fecha en formato legible (ej. "15 Junio 2024")
//     en vez del formato YYYY-MM-DD del input nativo
//
// Se aplica en todos los formularios que tenian input type="date":
//   1) components/DatePickerModal.tsx (ARCHIVO NUEVO) -- el componente
//      reutilizable. Acepta value en formato YYYY-MM-DD y devuelve
//      onChange en el mismo formato, compatible con el resto de la app.
//   2) app/prevencion/page.tsx (11 fechas reemplazadas)
//   3) app/mascota/vacuna-inicial/page.tsx (2 fechas reemplazadas)
//   4) app/mascota/nueva/page.tsx (1 fecha reemplazada: fecha nacimiento)
//
// Como correrlo: node generar_68_datepicker.js
// Confirma "OK" para los 4 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('components/DatePickerModal.tsx', "");
escribir('app/prevencion/page.tsx', "");
escribir('app/mascota/vacuna-inicial/page.tsx', "");
escribir('app/mascota/nueva/page.tsx', "");
